import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './Login.css';

const AdminLogin = ({ onLoginSuccess }) => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');

    const handleLogin = async (e) => {
        e.preventDefault();
        try {
            const response = await fetch('http://localhost:5000/login', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email, password })
            });

            localStorage.setItem("token", response.data.token);
            localStorage.setItem("user", JSON.stringify(response.data.user));
            
            const data = await response.json();
            if (response.ok) {
                onLoginSuccess(data.user);
            } else {
                setError(data.message || "Đăng nhập thất bại!");
            }
        } catch (err) {
            setError("Lỗi kết nối đến server: " + err.message);
        }
    }; 
    return (
        <div className="admin-login-page">
            <div className="admin-login-box">
                <div className="admin-login-header">
                    <h1>E-TECH ADMIN</h1>
                    <p>Hệ thống quản trị nội bộ</p>
                </div>

                <form className="admin-login-form" onSubmit={handleLogin}>
                    {error && <div className="login-error-msg">{error}</div>}
                    
                    <div className="input-group">
                        <label>Tài khoản quản trị</label>
                        <div className="input-wrapper">
                            <i className="fa-solid fa-envelope"></i>
                            <input 
                                type="email" 
                                placeholder="admin@gmail.com"
                                value={email} 
                                onChange={(e) => setEmail(e.target.value)} 
                                required 
                            />
                        </div>
                    </div>

                    <div className="input-group">
                        <label>Mật khẩu</label>
                        <div className="input-wrapper">
                            <i className="fa-solid fa-lock"></i>
                            <input 
                                type="password" 
                                placeholder="Điền mật khẩu tại đây"
                                value={password} 
                                onChange={(e) => setPassword(e.target.value)} 
                                required 
                            />
                        </div>
                    </div>

                    <button type="submit" className="btn-admin-login">
                        Xác nhận đăng nhập
                    </button>
                </form>

                <div className="admin-login-footer">
                    <p>&copy; E-Tech Management System</p>
                </div>
            </div>
        </div>
    );
};

export default AdminLogin;
